import { createClient } from '@supabase/supabase-js'
import { apiUrl, appConfig } from '../shared/utils/config.js'
import { auth } from '../shared/utils/auth.js'
import { apiFetch as sharedApiFetch } from '../shared/utils/api.js'
import { supabase as sharedSupabase } from '../shared/utils/supabase.js'
import { escapeHTML } from './format.js'

// Store iframe URLs generated by search.
export const currentIframeUrls = window.currentIframeUrls = {
  noapc: "",
  resurchify: "",
  wos: ""
}

// Embedded lookup data is loaded from /tapchi/embedded-data.js before this module.
export const hdgsnnData = window.hdgsnnData || []
export const pdfData = window.pdfData || []

if (!sharedSupabase) {
  throw new Error('Missing Supabase configuration. Create .env from .env.example.')
}

export const db = sharedSupabase
export const publicDb = createClient(
  appConfig.SUPABASE_URL,
  appConfig.SUPABASE_PUBLISHABLE_KEY,
  {
    auth: {
      storageKey: 'lelong-public-readonly',
      persistSession: false,
      autoRefreshToken: false,
      detectSessionInUrl: false
    }
  }
)

const initialAuthUrl = new URL(location.href)
const initialAuthHash = new URLSearchParams(initialAuthUrl.hash.slice(1))
const initialPasswordRecovery = initialAuthUrl.searchParams.get('recovery') === '1'
  || initialAuthUrl.searchParams.get('type') === 'recovery'
  || initialAuthHash.get('type') === 'recovery'
    let currentSession = null;
    let currentAccount = null;
    let currentAuthMode = 'login';
    let accountRefreshPromise = null;
    let adminDashboardPromise = null;
    let adminPlanVisible = 8;
    let adminPlanSearch = '';
    let adminPlanProduct = 'all';
    let adminPlanStatus = 'all';
    let adminLookupSources = [];
    let accountRealtimeChannel = null;
    let accountRealtimeUserId = null;
    let accountRealtimeTimer = null;
    let adminRealtimeChannel = null;
    let adminRealtimeTimer = null;
    let adminRealtimeFallbackTimer = null;
    let paymentPollTimer = null;
    let activePaymentCode = null;
    let passwordRecoveryActive = false;
    let passwordRecoveryRequested = initialPasswordRecovery;
    let configuredTrialDays = 14;
    let configuredPlanPrice = 0;
    let publicConfigPromise = null;
    let backendUnavailable = false;
    let backendUnavailableReason = '';

    function loadPublicConfig() {
      if (publicConfigPromise) return publicConfigPromise;
      publicConfigPromise = fetch(apiUrl('/api/public/config'))
        .then(response => response.ok ? response.json() : Promise.reject(new Error('Không tải được cấu hình')))
        .then(config => {
          configuredTrialDays = Number(config.trial_days ?? 14);
          configuredPlanPrice = Number(config.price_vnd || 0);
          updateConfiguredPlanPrice();
          return configuredTrialDays;
        })
        .catch(() => configuredTrialDays);
      return publicConfigPromise;
    }

    function updateConfiguredPlanPrice(account = currentAccount) {
      const chatPlan = account?.services?.plans?.find(plan => plan.product_code === 'chatbox_ai');
      const price = Number(chatPlan?.price_vnd || configuredPlanPrice || 0);
      const buttonLabel = document.getElementById('vipPurchaseLabel');
      if (buttonLabel) buttonLabel.textContent = price > 0
        ? `Mua thêm lượt · ${formatVnd(price)}`
        : 'Mua thêm lượt';
      return price;
    }

    function setUserMessage(message = '', type = '') {
      const element = document.getElementById('authMessage');
      if (!element) return;
      element.textContent = message;
      element.className = `vip-message ${type}`.trim();
    }

    function hasLocalAuthForm() {
      return Boolean(document.getElementById('authView') && document.getElementById('authForm'));
    }

    function redirectToSharedAuth(mode = 'login') {
      const nextMode = mode === 'register' || mode === 'reset' ? mode : 'login';
      if (typeof window.openMixingAuth === 'function') {
        window.openMixingAuth(nextMode);
      } else {
        window.dispatchEvent(new CustomEvent('mixing:open-auth', { detail: { mode: nextMode } }));
      }
    }

    function setAuthMode(mode) {
      currentAuthMode = mode;
      if (!hasLocalAuthForm()) {
        redirectToSharedAuth(mode);
        return;
      }
      const registering = mode === 'register';
      document.getElementById('loginTab').classList.toggle('active', !registering);
      document.getElementById('registerTab').classList.toggle('active', registering);
      document.getElementById('authNameField').style.display = registering ? 'grid' : 'none';
      document.getElementById('authName').required = registering;
      document.getElementById('authPassword').autocomplete = registering ? 'new-password' : 'current-password';
      document.getElementById('authHeading').textContent = registering ? 'Tạo tài khoản mới' : 'Chào mừng trở lại';
      document.getElementById('authLead').textContent = registering
        ? `Đăng ký để nhận ${configuredTrialDays} ngày dùng thử miễn phí và bắt đầu trò chuyện cùng AI.`
        : 'Đăng nhập để tiếp tục sử dụng Trợ lý Tạp chí AI.';
      document.getElementById('authSubmitLabel').textContent = registering ? 'Tạo tài khoản' : 'Đăng nhập';
      document.getElementById('authWelcome').style.display = 'block';
      document.getElementById('authTabs').style.display = 'flex';
      document.getElementById('authForm').style.display = 'grid';
      document.getElementById('resetView').style.display = 'none';
      setUserMessage();
    }

    function showPasswordRecovery() {
      if (!hasLocalAuthForm()) {
        passwordRecoveryActive = true;
        redirectToSharedAuth('reset');
        return;
      }
      passwordRecoveryActive = true;
      document.getElementById('accountVipModal')?.classList.add('open');
      document.getElementById('authView').style.display = 'block';
      document.getElementById('accountView').style.display = 'none';
      document.getElementById('paymentBox').classList.remove('open');
      document.getElementById('paymentQr').removeAttribute('src');
      document.getElementById('authWelcome').style.display = 'none';
      document.getElementById('authTabs').style.display = 'none';
      document.getElementById('authForm').style.display = 'none';
      document.getElementById('resetView').style.display = 'grid';
      setUserMessage('Liên kết hợp lệ. Hãy tạo mật khẩu mới.', 'success');
      setTimeout(() => document.getElementById('newPassword').focus(), 0);
    }

    function togglePasswordVisibility(inputId, button) {
      const input = document.getElementById(inputId);
      const showing = input.type === 'text';
      input.type = showing ? 'password' : 'text';
      button.innerHTML = `<i class="fas fa-${showing ? 'eye' : 'eye-slash'}"></i>`;
      button.setAttribute('aria-label', showing ? 'Hiện mật khẩu' : 'Ẩn mật khẩu');
    }

    async function openUserModal(forceModal = false) {
      if (currentSession && !forceModal && !passwordRecoveryActive && !passwordRecoveryRequested) {
        await openAccountPortal();
        return;
      }
      if (!currentSession && !hasLocalAuthForm()) {
        if (forceModal) currentAuthMode = 'login';
        redirectToSharedAuth(currentAuthMode);
        return;
      }
      const userModal = document.getElementById('accountVipModal');
      if (!userModal) return;
      userModal.classList.add('open');
      const recovering = passwordRecoveryActive || passwordRecoveryRequested;
      const authView = document.getElementById('authView');
      const accountView = document.getElementById('accountView');
      if (authView) authView.style.display = recovering || !currentSession ? 'block' : 'none';
      if (accountView) accountView.style.display = currentSession && !recovering ? 'block' : 'none';
      if (currentSession && !currentAccount) void refreshAccount();
    }

    function closeUserModal() {
      document.getElementById('accountVipModal')?.classList.remove('open');
      stopPaymentPolling();
    }

    async function submitAuth(event) {
      event.preventDefault();
      const email = document.getElementById('authEmail').value.trim();
      const password = document.getElementById('authPassword').value;
      const displayName = document.getElementById('authName').value.trim();
      const submit = document.getElementById('authSubmit');
      submit.disabled = true;
      setUserMessage('Đang xử lý...');
      try {
        if (currentAuthMode === 'register') {
          const { session, error } = await auth.signUp(email, password, { display_name: displayName }, { emailRedirectTo: `${location.origin}${location.pathname}` });
          if (error) throw error;
          if (!session) {
            setUserMessage('Đăng ký thành công. Hãy kiểm tra email để xác minh tài khoản.', 'success');
          } else {
            closeUserModal();
          }
        } else {
          const { error } = await auth.signIn(email, password);
          if (error) throw error;
          closeUserModal();
        }
      } catch (error) {
        setUserMessage(error.message || 'Không thể xác thực tài khoản.', 'error');
      } finally {
        submit.disabled = false;
      }
    }

    async function requestPasswordReset() {
      const email = document.getElementById('authEmail').value.trim();
      if (!email) {
        setUserMessage('Nhập email trước khi yêu cầu đặt lại mật khẩu.', 'error');
        document.getElementById('authEmail').focus();
        return;
      }
      const button = document.getElementById('passwordResetRequest');
      button.disabled = true;
      button.textContent = 'Đang gửi...';
      const redirectUrl = new URL(location.href);
      redirectUrl.search = '';
      redirectUrl.hash = '';
      redirectUrl.searchParams.set('recovery', '1');
      try {
        const { error } = await auth.resetPassword(email, redirectUrl.toString());
        if (error) throw error;
        setUserMessage('Đã gửi liên kết đặt lại mật khẩu. Vui lòng kiểm tra hộp thư và thư rác.', 'success');
      } catch (error) {
        setUserMessage(error.message || 'Không thể gửi email đặt lại mật khẩu.', 'error');
      } finally {
        button.disabled = false;
        button.textContent = 'Quên mật khẩu?';
      }
    }

    function passwordRuleState(password) {
      return {
        length: password.length >= 8,
        lower: /[a-z]/.test(password),
        upper: /[A-Z]/.test(password),
        number: /[0-9]/.test(password),
        special: /[^A-Za-z0-9\s]/.test(password)
      };
    }

    function updatePasswordRules(password) {
      const rules = passwordRuleState(password);
      document.querySelectorAll('#passwordRules .password-rule').forEach(element => {
        const valid = Boolean(rules[element.dataset.rule]);
        element.classList.toggle('valid', valid);
        element.querySelector('i').className = valid ? 'fas fa-circle-check' : 'fas fa-circle';
      });
      return Object.values(rules).every(Boolean);
    }

    async function ensurePasswordRecoverySession() {
      const session = await auth.getSession();
      const sessionData = { session };
      if (sessionData.session) return sessionData.session;

      const accessToken = initialAuthHash.get('access_token');
      const refreshToken = initialAuthHash.get('refresh_token');
      if (accessToken && refreshToken) {
        const { data, error } = await db.auth.setSession({
          access_token: accessToken,
          refresh_token: refreshToken
        });
        if (!error && data.session) return data.session;
      }

      const code = initialAuthUrl.searchParams.get('code');
      if (code) {
        const { data, error } = await db.auth.exchangeCodeForSession(code);
        if (!error && data.session) return data.session;
      }
      throw new Error('Liên kết đặt lại mật khẩu đã hết hạn hoặc đã được sử dụng. Hãy yêu cầu liên kết mới.');
    }

    async function saveNewPassword(event) {
      event.preventDefault();
      const password = document.getElementById('newPassword').value;
      const confirmation = document.getElementById('confirmNewPassword').value;
      const button = document.getElementById('saveNewPasswordButton');
      if (!updatePasswordRules(password)) {
        setUserMessage('Mật khẩu chưa đáp ứng đầy đủ các điều kiện bảo mật.', 'error');
        return;
      }
      if (password !== confirmation) {
        setUserMessage('Hai mật khẩu chưa trùng khớp.', 'error');
        return;
      }
      button.disabled = true;
      button.innerHTML = '<i class="fas fa-circle-notch fa-spin"></i>&nbsp; Đang cập nhật...';
      try {
        await ensurePasswordRecoverySession();
        const { error } = await auth.updatePassword(password);
        if (error) throw error;
        passwordRecoveryActive = false;
        passwordRecoveryRequested = false;
        document.getElementById('resetView').reset();
        updatePasswordRules('');
        await auth.signOut();
        currentSession = null;
        currentAccount = null;
        const cleanUrl = new URL(location.href);
        cleanUrl.searchParams.delete('recovery');
        cleanUrl.searchParams.delete('code');
        cleanUrl.hash = '';
        history.replaceState({}, '', `${cleanUrl.pathname}${cleanUrl.search}`);
        setAuthMode('login');
        document.getElementById('authView').style.display = 'block';
        document.getElementById('accountView').style.display = 'none';
        document.getElementById('accountVipModal')?.classList.add('open');
        setUserMessage('Đổi mật khẩu thành công. Hãy đăng nhập bằng mật khẩu mới.', 'success');
      } catch (error) {
        const message = /auth session missing/i.test(error.message || '')
          ? 'Liên kết đặt lại mật khẩu đã hết hạn hoặc đã được sử dụng. Hãy yêu cầu liên kết mới.'
          : error.message;
        setUserMessage(message || 'Không thể cập nhật mật khẩu.', 'error');
      } finally {
        button.disabled = false;
        button.innerHTML = '<i class="fas fa-floppy-disk"></i>&nbsp; Lưu mật khẩu mới';
      }
    }

    async function signOutUser() {
      activePaymentCode = null;
      stopPaymentPolling();
      resetRealtimeSubscriptions();
      await auth.signOut();
      currentAccount = null;
      window.location.replace('/');
    }

    async function apiFetch(path, options = {}) {
      const session = await auth.getSession();
      if (!session?.access_token) throw new Error('Bạn cần đăng nhập.');
      currentSession = session;
      return sharedApiFetch(path, options);
    }
    function renderAccount(account) {
      if (!account) return;
      updateConfiguredPlanPrice(account);
      document.getElementById('accountEmail').textContent = account.user.email || '';
      const status = document.getElementById('vipStatus');
      const chatProduct = account.services?.products?.find(product => product.code === 'chatbox_ai');
      const trialDays = Number(chatProduct?.trial_days || 14);
      const isAdmin = account.role === 'admin' || isAdminAccount(account);
      status.textContent = isAdmin
        ? 'VIP Vĩnh viễn (Admin)'
        : account.is_trial
          ? `Đang dùng thử miễn phí ${trialDays} ngày`
          : getRemainingCredits(account) > 0 ? 'VIP đang hoạt động' : 'Đã hết lượt VIP';
      status.className = account.is_vip ? 'vip-active' : 'vip-inactive';
      const expiryRow = document.getElementById('vipExpiryRow');
      const expiry = account.is_trial ? account.subscription?.trial_ends_at : null;
      expiryRow.style.display = expiry && !isAdmin ? 'flex' : 'none';
      if (expiry && !isAdmin) document.getElementById('vipExpiry').textContent = new Date(expiry).toLocaleDateString('vi-VN');
      const limit = chatProduct?.entitlement?.trial_daily_limit || chatProduct?.trial_daily_limit || 30;
      document.getElementById('vipUsage').textContent = isAdmin ? 'Vô hạn' : account.is_trial ? `${account.usage_today || 0}/${limit} hôm nay` : `${getRemainingCredits(account)} lượt`;
      document.getElementById('vipWalletBalance').textContent = isAdmin ? 'Vô hạn' : formatVnd(getWalletBalance(account));
      const chatAccessNote = document.getElementById('chat-access-note');
      if (chatAccessNote) chatAccessNote.style.display = account.is_vip ? 'none' : 'block';
      renderPortalAccount(account);
    }

    let adminDashboardData = null;
    let userChartMode = 'week';
    let adminChartMode = 'day';
    let portalHistoryPushed = false;
    const portalPageAliases = {
      dashboard: { admin: 'adminDashboard', client: 'userOverview' },
      invoices: { admin: 'adminInvoices', client: 'userTransactions' },
      payments: { admin: 'adminInvoices', client: 'userTransactions' },
      lookup: { admin: 'adminLookupSources', client: 'userOverview' },
      sources: { admin: 'adminLookupSources', client: 'userOverview' },
      users: { admin: 'adminUsers', client: 'userOverview' },
      settings: { admin: 'adminSettings', client: 'userOverview' },
      userOverview: { admin: 'adminDashboard', client: 'userOverview' },
      userTransactions: { admin: 'adminInvoices', client: 'userTransactions' },
      adminDashboard: { admin: 'adminDashboard', client: 'userOverview' },
      adminInvoices: { admin: 'adminInvoices', client: 'userTransactions' },
      adminLookupSources: { admin: 'adminLookupSources', client: 'userOverview' },
      adminUsers: { admin: 'adminUsers', client: 'userOverview' },
      adminSettings: { admin: 'adminSettings', client: 'userOverview' }
    };

    function isAdminAccount(account = currentAccount) {
      const accountUser = account?.user || currentAccount?.user || {};
      const sessionUser = currentSession?.user || {};
      const role = sessionUser.app_metadata?.role
        || sessionUser.user_metadata?.role
        || accountUser.app_metadata?.role
        || accountUser.user_metadata?.role
        || account?.role
        || currentAccount?.role;
      return role === 'admin'
        || account?.role === 'admin'
        || currentAccount?.role === 'admin'
        || account?.services?.is_admin === true
        || currentAccount?.services?.is_admin === true;
    }

    async function detectAdminFromSupabase(user = currentSession?.user) {
      if (!user || !db) return false;
      const metadataRole = user.app_metadata?.role || user.user_metadata?.role;
      if (metadataRole === 'admin') return true;
      try {
        const { data, error } = await db.rpc('is_magazine_admin');
        if (!error && data === true) return true;
      } catch (_) { }
      try {
        const { data } = await db.from('admin_users').select('email').ilike('email', user.email || '').maybeSingle();
        if (data) return true;
      } catch (_) { }
      try {
        const { data } = await db.from('profiles').select('role').or(`user_id.eq.${user.id},id.eq.${user.id}`).maybeSingle();
        if (data?.role === 'admin') return true;
      } catch (_) { }
      return false;
    }

    async function buildFallbackAccount(error = null) {
      const user = currentSession?.user;
      if (!user) return null;
      backendUnavailable = true;
      backendUnavailableReason = error?.message || 'Backend đang tạm thời chưa sẵn sàng';
      const isAdmin = await detectAdminFromSupabase(user);
      const fallback = {
        user,
        role: isAdmin ? 'admin' : 'user',
        payments: [],
        usage: [],
        services: {
          is_admin: isAdmin,
          products: [],
          plans: [],
          wallet_balance_vnd: 0,
          unavailable: true,
          error: backendUnavailableReason
        },
        is_trial: false,
        is_vip: isAdmin,
        remaining_credits: 0,
        wallet_balance_vnd: 0
      };
      currentAccount = fallback;
      renderAccount(fallback);
      return fallback;
    }

    function formatPortalDate(value, fallback = 'Chưa kích hoạt') {
      if (!value) return fallback;
      const date = new Date(value);
      return Number.isNaN(date.getTime()) ? fallback : date.toLocaleDateString('vi-VN');
    }

    function formatVnd(value) {
      return `${Number(value || 0).toLocaleString('vi-VN')} đ`;
    }

    function getRemainingCredits(account) {
      const value = account?.remaining_credits ?? account?.subscription?.ai_credits_remaining;
      return Number.isFinite(Number(value)) ? Math.max(0, Number(value)) : 0;
    }

    function getWalletBalance(account) {
      const value = account?.wallet_balance_vnd ?? account?.subscription?.wallet_balance_vnd;
      return Number.isFinite(Number(value)) ? Math.max(0, Number(value)) : 0;
    }

    function renderPortalAccount(account) {
      const user = account?.user || currentSession?.user || {};
      const sessionUser = currentSession?.user || {};
      const name = sessionUser.user_metadata?.display_name || user.user_metadata?.display_name || user.email?.split('@')[0] || 'Người dùng';
      const firstLetter = name.trim().charAt(0).toUpperCase() || 'U';
      const admin = isAdminAccount(account);
      const paidPayments = (account?.payments || []).filter(payment => payment.status === 'paid');
      const chatProduct = account?.services?.products?.find(product => product.code === 'chatbox_ai');
      const chatEntitlement = chatProduct?.entitlement || {};
      const start = account?.is_trial
        ? chatEntitlement.trial_started_at
        : chatEntitlement.monthly_started_at || paidPayments.find(payment => payment.product_code === 'chatbox_ai')?.paid_at;
      const limit = chatProduct?.entitlement?.trial_daily_limit || chatProduct?.trial_daily_limit || 30;
      const trialDays = Number(chatProduct?.trial_days || 14);
      const used = Number(chatEntitlement.daily_usage ?? account?.usage_today ?? 0);
      const remainingCredits = getRemainingCredits(account);
      const walletBalance = account?.services?.is_admin
        ? 0 : Number(account?.services?.wallet_balance_vnd ?? getWalletBalance(account));
      const lastPaidCredits = Number(paidPayments.find(payment => Number(payment.credits_granted || 0) > 0)?.credits_granted
        || remainingCredits || 0);
      const creditTotal = Math.max(1, remainingCredits + Math.max(0, lastPaidCredits - remainingCredits));
      const percent = admin ? 0 : account?.is_trial
        ? Math.min(100, Math.round((used / Math.max(1, limit)) * 100))
        : Math.min(100, Math.round(((creditTotal - remainingCredits) / creditTotal) * 100));

      document.getElementById('accountPortal').classList.toggle('admin-enabled', admin);
      const overviewNav = document.getElementById('portalOverviewNav');
      if (overviewNav) {
        overviewNav.dataset.page = admin ? 'adminDashboard' : 'userOverview';
        overviewNav.dataset.portalPage = admin ? 'adminDashboard' : 'userOverview';
        overviewNav.removeAttribute('onclick');
        overviewNav.innerHTML = admin
          ? '<i class="fas fa-chart-pie"></i><span>Dashboard admin</span>'
          : '<i class="fas fa-gauge-high"></i><span>Tổng quan</span>';
      }
      const transactionNav = document.getElementById('portalTransactionsNav');
      if (transactionNav) {
        transactionNav.dataset.page = admin ? 'adminInvoices' : 'userTransactions';
        transactionNav.dataset.portalPage = admin ? 'adminInvoices' : 'userTransactions';
        transactionNav.removeAttribute('onclick');
        transactionNav.innerHTML = admin
          ? '<i class="fas fa-file-invoice-dollar"></i><span>Hóa đơn gần đây</span>'
          : '<i class="fas fa-clock-rotate-left"></i><span>Lịch sử giao dịch</span>';
      }
      const adminInvoicesNav = document.getElementById('adminInvoicesNav');
      if (adminInvoicesNav) adminInvoicesNav.style.display = admin ? 'none' : '';
      const adminDashboardNav = document.getElementById('adminDashboardNav');
      if (adminDashboardNav) adminDashboardNav.style.display = admin ? 'none' : '';
      document.getElementById('portalRoleLabel').textContent = admin ? 'Hệ thống quản trị' : 'Tài khoản người dùng';
      document.getElementById('portalProfileName').textContent = name;
      document.getElementById('portalAvatar').textContent = firstLetter;
      document.getElementById('portalVipPlan').textContent = admin
        ? 'VIP VĨNH VIỄN (ADMIN)'
        : account?.is_trial
          ? `DÙNG THỬ ${trialDays} NGÀY`
          : account?.is_vip ? 'DỊCH VỤ ĐANG HOẠT ĐỘNG'
            : 'TÀI KHOẢN STANDARD';
      document.getElementById('portalVipBadge').innerHTML = admin
        ? '<i class="fas fa-crown"></i>&nbsp; ADMIN VIP'
        : account?.is_trial
          ? '<i class="fas fa-hourglass-half"></i>&nbsp; FREE TRIAL'
          : account?.is_vip ? '<i class="fas fa-circle-check"></i>&nbsp; ACTIVE'
            : '<i class="fas fa-clock"></i>&nbsp; INACTIVE';
      document.getElementById('portalVipStart').textContent = admin ? 'Hệ thống' : formatPortalDate(start);
      document.getElementById('portalVipEnd').textContent = admin ? 'Vô hạn' : account?.is_trial ? formatPortalDate(chatEntitlement.trial_ends_at, 'Chưa có') : `${remainingCredits} lượt · ${formatVnd(walletBalance)}`;
      document.getElementById('portalVipPercent').textContent = admin ? 'Vô hạn' : account?.is_trial ? `${percent}%` : `${remainingCredits} lượt`;
      document.getElementById('portalVipProgress').style.width = admin ? '100%' : `${percent}%`;
      document.getElementById('portalVipProgressLabel').textContent = admin ? 'Lượt dùng: Vô hạn' : account?.is_trial ? `Lượt dùng hôm nay (${used}/${limit})` : `Đã dùng ${Math.max(0, creditTotal - remainingCredits)}/${creditTotal} lượt`;
      document.getElementById('portalWalletBalance').textContent = admin ? 'Vô hạn' : formatVnd(walletBalance);
      document.getElementById('portalWalletNote').textContent = admin
        ? 'Tài khoản admin không cần nạp số dư.'
        : walletBalance > 0
          ? 'Số dư sẽ được dùng để tự gia hạn khi đủ giá gói.'
          : 'Nạp số dư để tự gia hạn gói VIP khi hết lượt.';
      renderPortalServices(account?.services);
    }

    const serviceIcons = {
      chatbox_ai: 'fa-comments',
      magazine_export: 'fa-file-export',
      magazine_ai_review: 'fa-wand-magic-sparkles'
    };

    function renderPortalServices(services) {
      const container = document.getElementById('portalServiceCards');
      if (!container) return;
      if (!services?.products?.length) {
        container.innerHTML = '<p style="color:#94a3b8;">Chưa tải được thông tin dịch vụ.</p>';
        return;
      }
      container.innerHTML = services.products.map(product => {
        const entitlement = product.entitlement || {};
        const trialActive = entitlement.trial_ends_at && new Date(entitlement.trial_ends_at) > new Date();
        const monthlyActive = entitlement.monthly_ends_at && new Date(entitlement.monthly_ends_at) > new Date();
        const plans = (services.plans || []).filter(plan => plan.product_code === product.code);
        const renewal = product.auto_renew || {};
        const status = product.unlimited ? 'Vô hạn'
          : trialActive ? `Trial đến ${formatPortalDate(entitlement.trial_ends_at)}`
            : `${Number(entitlement.daily_remaining ?? entitlement.monthly_balance ?? 0)}/${Number(entitlement.daily_limit ?? entitlement.monthly_balance ?? 0)} lượt còn lại hôm nay · ${Number(entitlement.credit_balance || 0)} lượt lẻ`;
        return `<article class="portal-panel" style="padding:18px;">
          <h3 style="margin:0 0 6px;"><i class="fas ${serviceIcons[product.code] || 'fa-circle'}" style="color:#2f6df6;"></i> ${escapeHTML(product.name)}</h3>
          <p style="margin:0 0 14px;color:#64748b;">${escapeHTML(status)}${monthlyActive ? ` · hết hạn ${escapeHTML(formatPortalDate(entitlement.monthly_ends_at))}` : ''}</p>
          ${product.unlimited ? '<span class="portal-pill green">Admin vô hạn</span>' : `
            <select class="publishing-select" data-service-plan-select="${product.code}" style="width:100%;margin-bottom:10px;">
              ${plans.map(plan => `<option value="${escapeHTML(plan.id)}" ${renewal.plan_id === plan.id ? 'selected' : ''}>${escapeHTML(plan.name)} · ${plan.credits} ${plan.billing_type === 'monthly' ? 'lượt/ngày' : 'lượt'} · ${formatVnd(plan.price_vnd)}</option>`).join('') || '<option value="">Chưa có gói đang bán</option>'}
            </select>
            <button class="portal-btn primary" type="button" data-open-shared-purchase ${plans.length ? '' : 'disabled'}>Mua gói</button>
            <label style="display:flex;align-items:center;gap:8px;margin-top:12px;font-size:13px;">
              <input type="checkbox" data-auto-renew="${product.code}" ${renewal.enabled ? 'checked' : ''} ${plans.length ? '' : 'disabled'}>
              Tự gia hạn gói đã chọn
            </label>`}
        </article>`;
      }).join('');
    }

    function maybeShowTrialWelcome(services) {
      const userId = currentSession?.user?.id;
      if (!userId || !services?.products?.length) return;
      const key = `mixing-trial-welcome:${userId}`;
      if (localStorage.getItem(key)) return;
      const trialProducts = services.products.filter(product => product.entitlement?.trial_started_at);
      if (trialProducts.length < 3) return;
      document.getElementById('trialWelcomeModal')?.classList.add('open');
      localStorage.setItem(key, '1');
    }

    function isPortalRoute() {
      return location.pathname.startsWith('/portal');
    }

    function resolvePortalPage(page = 'dashboard', admin = isAdminAccount()) {
      const route = portalPageAliases[page] || portalPageAliases.dashboard;
      return admin ? route.admin : route.client;
    }

    function getRequestedPortalPage() {
      const params = new URLSearchParams(location.search);
      const queryPage = params.get('page');
      if (queryPage) return queryPage;
      return location.hash.replace(/^#/, '');
    }

    function syncShellActiveFromPortalPage(page = getRequestedPortalPage()) {
      const shellId = ({
        dashboard: 'dashboard',
        invoices: 'invoices',
        payments: 'payments',
        lookup: 'lookup',
        sources: 'lookup',
        users: 'users',
        settings: 'settings'
      })[page] || 'dashboard';
      document.querySelectorAll('[data-shell-nav]').forEach(link => {
        link.setAttribute('aria-current', link.dataset.shellNav === shellId ? 'page' : 'false');
      });
    }

    function getPortalPageUrlFromLink(link) {
      if (!link) return null;
      try {
        const url = new URL(link.getAttribute('href') || '', location.href);
        if (url.origin !== location.origin) return null;
        if (!url.pathname.startsWith('/portal')) return null;
        if (!url.searchParams.get('page')) return null;
        return url;
      } catch (_) {
        return null;
      }
    }

    async function routePortalUrl(url, { replace = false } = {}) {
      if (!url) return;
      const next = `${url.pathname}${url.search}${url.hash}`;
      const current = `${location.pathname}${location.search}${location.hash}`;
      if (next !== current) {
        if (replace) history.replaceState(history.state, '', next);
        else history.pushState(history.state, '', next);
      }
      syncShellActiveFromPortalPage(url.searchParams.get('page'));
      await handlePortalRouting();
    }

    function handlePortalLinkClick(event) {
      const link = event.target.closest?.('a[href]');
      if (!link || link.closest('[data-shell-action="buy-credits"]')) return;
      const url = getPortalPageUrlFromLink(link);
      if (!url) return;
      event.preventDefault();
      event.stopPropagation();
      event.stopImmediatePropagation?.();
      void routePortalUrl(url);
    }

    async function handlePortalRouting() {
      const requestedPage = getRequestedPortalPage();
      syncShellActiveFromPortalPage(requestedPage);
      if (!requestedPage) {
        if (isPortalRoute()) {
          if (!currentSession) openUserModal(true);
          else {
            const account = currentAccount || await refreshAccount();
            const page = resolvePortalPage('dashboard', isAdminAccount(account));
            await openAccountPortal(page, { updateUrl: false });
            switchPortalPage(page, { updateUrl: false });
          }
        } else {
          closeAccountPortal();
        }
        return;
      }
      if (!currentSession) {
        openUserModal(true);
        return;
      }
      const account = currentAccount || await refreshAccount();
      const admin = isAdminAccount(account);
      const page = resolvePortalPage(requestedPage, admin);
      await openAccountPortal(page, { updateUrl: false });
      switchPortalPage(page, { updateUrl: false });
    }

    async function openAccountPortal(page = 'userOverview', { updateUrl = true } = {}) {
      if (!currentSession) {
        openUserModal(true);
        return;
      }
      closeUserModal();
      const account = currentAccount || await refreshAccount();
      renderPortalAccount(account || { user: currentSession.user, is_vip: false });
      renderPortalTables();
      renderPortalCharts();
      if (isAdminAccount(account) && page === 'userOverview') page = 'adminDashboard';
      switchPortalPage(page, { updateUrl });
      const portal = document.getElementById('accountPortal');
      togglePortalNav(false);
      portal.classList.add('open');
      portal.setAttribute('aria-hidden', 'false');
      document.body.classList.add('portal-open');
      document.body.style.overflow = 'hidden';
      if (isPortalRoute() && updateUrl) {
        updatePortalUrl(page);
      } else if (!portalHistoryPushed) {
        history.pushState({ accountPortal: true }, '', location.href);
        portalHistoryPushed = true;
      }
    }

    function closeAccountPortal(fromHistory = false) {
      if (isPortalRoute() && !fromHistory) {
        window.location.href = '/tapchi/';
        return;
      }
      const portal = document.getElementById('accountPortal');
      if (!portal) return;
      togglePortalNav(false);
      if (portal.contains(document.activeElement)) document.activeElement.blur();
      portal.classList.remove('open');
      portal.setAttribute('aria-hidden', 'true');
      document.body.classList.remove('portal-open');
      document.body.style.overflow = '';
      if (location.hash) {
        history.pushState(null, '', location.pathname + location.search);
      }
      if (portalHistoryPushed && !fromHistory) {
        portalHistoryPushed = false;
        history.back();
      } else if (fromHistory) {
        portalHistoryPushed = false;
      }
    }

    window.addEventListener('popstate', () => {
      if (isPortalRoute()) void handlePortalRouting();
      else {
        const portal = document.getElementById('accountPortal');
        if (portal?.classList.contains('open')) closeAccountPortal(true);
      }
    });

    window.addEventListener('hashchange', handlePortalRouting);
    window.addEventListener('mixing:portal-route', handlePortalRouting);

    function togglePortalNav(force) {
      const portal = document.getElementById('accountPortal');
      if (!portal) return;
      const open = typeof force === 'boolean' ? force : !portal.classList.contains('nav-open');
      portal.classList.toggle('nav-open', open);
      const button = portal.querySelector('.portal-menu-toggle');
      if (button) {
        button.setAttribute('aria-label', open ? 'Đóng menu tài khoản' : 'Mở menu tài khoản');
        button.innerHTML = `<i class="fas fa-${open ? 'xmark' : 'bars'}"></i>`;
      }
    }

    function switchPortalPage(pageId, { updateUrl = true } = {}) {
      if (pageId === 'userOverview' && isAdminAccount()) pageId = 'adminDashboard';
      if (pageId === 'userTransactions' && isAdminAccount()) pageId = 'adminInvoices';
      const page = document.getElementById(pageId);
      if (!page || (pageId.startsWith('admin') && !isAdminAccount())) return;
      document.querySelectorAll('.portal-page').forEach(item => item.classList.toggle('active', item.id === pageId));
      document.querySelectorAll('.portal-nav button[data-page]').forEach(button => button.classList.toggle('active', button.dataset.page === pageId));
      const labels = {
        userOverview: ['Chào mừng trở lại!', 'Quản lý tài khoản và theo dõi gói VIP của bạn tại đây.'],
        userTransactions: ['Lịch sử giao dịch', 'Theo dõi toàn bộ hoạt động thanh toán trên tài khoản.'],
        adminDashboard: ['Trình điều khiển', 'Dữ liệu thực từ thanh toán, tài khoản và lượt dùng AI.'],
        adminUsers: ['Quản lý người dùng', 'Theo dõi số lượng tài khoản và trạng thái VIP.'],
        adminInvoices: ['Quản lý hóa đơn', 'Theo dõi thanh toán, số lượt cộng và trạng thái giao dịch.'],
        adminLookupSources: ['Nguồn tra cứu', 'Tạo iframe hoặc liên kết ngoài cho các hệ thống tra cứu.'],
        adminSettings: ['Cài đặt hệ thống', 'Cấu hình giá VIP và số lượt sử dụng.']
      };
      const [title, subtitle] = labels[pageId] || labels.userOverview;
      document.getElementById('portalPageTitle').textContent = title;
      document.getElementById('portalPageSubtitle').textContent = subtitle;
      document.querySelector('.portal-main')?.scrollTo({ top: 0, behavior: 'smooth' });
      if (window.matchMedia('(max-width: 720px)').matches) togglePortalNav(false);
      if (pageId.startsWith('admin') && !adminDashboardData) void loadAdminDashboard();
      if (pageId === 'adminLookupSources') void loadAdminLookupSources();
      if (isPortalRoute() && updateUrl) updatePortalUrl(pageId);
    }

    function updatePortalUrl(pageId) {
      const publicPage = ({
        userOverview: 'dashboard',
        userTransactions: 'payments',
        adminDashboard: 'dashboard',
        adminInvoices: 'invoices',
        adminLookupSources: 'lookup',
        adminUsers: 'users',
        adminSettings: 'settings'
      })[pageId] || 'dashboard';
      const params = new URLSearchParams(location.search);
      params.set('page', publicPage);
      const next = `${location.pathname}?${params.toString()}`;
      const current = `${location.pathname}${location.search}${location.hash}`;
      if (next !== current) history.replaceState(history.state, '', next);
    }

    function transactionTableMarkup(rows) {
      const labels = { paid: 'Thành công', pending: 'Đang chờ', expired: 'Hết hạn', cancelled: 'Đã hủy', failed: 'Thất bại' };
      const body = rows.length ? rows.map(row => {
        const success = row.status === 'paid';
        const date = row.paid_at || row.created_at;
        const credits = Number(row.credits_granted || 0);
        const walletAmount = Number(row.wallet_amount_vnd || 0);
        const isWallet = row.order_type === 'wallet_topup';
        const productLabels = { chatbox_ai: 'Chatbox AI', magazine_export: 'Xuất Word/PDF', magazine_ai_review: 'AI Review' };
        const detail = isWallet ? `Nạp số dư ${formatVnd(walletAmount || row.amount_vnd)}` : `${productLabels[row.product_code] || row.plan_id || 'Gói dịch vụ'}${credits ? ` · ${credits.toLocaleString('vi-VN')} lượt` : ''}`;
        return `<tr><td data-label="Ngày">${escapeHTML(formatPortalDate(date, '-'))}</td><td data-label="Nội dung"><strong>${isWallet ? 'Nạp số dư' : 'Mua gói dịch vụ'}</strong><small style="display:block;color:#64748b;margin-top:3px;">${escapeHTML(detail)}</small></td><td data-label="Số tiền">${formatVnd(row.amount_vnd)}</td><td data-label="Trạng thái"><span class="portal-pill ${success ? 'green' : 'orange'}">${escapeHTML(labels[row.status] || row.status || '-')}</span></td></tr>`;
      }).join('') : '<tr><td colspan="4" style="text-align:center;color:#64748b;">Chưa có giao dịch.</td></tr>';
      return `<thead><tr><th>Ngày</th><th>Nội dung</th><th>Số tiền</th><th>Trạng thái</th></tr></thead><tbody>${body}</tbody>`;
    }

    function userTableMarkup(rows) {
      const body = rows.length ? rows.map(row => {
        const initials = String(row.name || 'U').split(' ').slice(-2).map(part => part[0]).join('').toUpperCase();
        const isAdmin = row.role === 'admin';
        const entitlementMap = new Map((row.entitlements || []).map(item => [item.product_code, item]));
          const serviceValue = code => isAdmin ? '∞' : Number(entitlementMap.get(code)?.daily_remaining || 0) + Number(entitlementMap.get(code)?.credit_balance || 0);
        const paid = (adminDashboardData?.payments || []).some(payment => payment.user_id === row.id && payment.status === 'paid' && payment.order_type !== 'wallet_topup');
        const services = `<span class="portal-pill">Chat ${serviceValue('chatbox_ai')}</span> <span class="portal-pill">Xuất ${serviceValue('magazine_export')}</span> <span class="portal-pill">Review ${serviceValue('magazine_ai_review')}</span>`;
        const status = isAdmin ? 'Admin' : paid ? 'Trả phí' : 'Miễn phí/Trial';
        return `<tr><td><div class="portal-user-cell"><span class="portal-mini-avatar">${escapeHTML(initials)}</span><strong>${escapeHTML(row.name || 'Người dùng')}</strong></div></td><td>${escapeHTML(row.email || '')}</td><td>${services}</td><td><span class="portal-pill ${isAdmin || paid ? 'green' : 'orange'}">${status}</span></td></tr>`;
      }).join('') : '<tr><td colspan="4" style="text-align:center;color:#64748b;">Chưa có người dùng.</td></tr>';
      return `<thead><tr><th>Khách hàng</th><th>Email liên hệ</th><th>Hạn mức dịch vụ</th><th>Trạng thái</th></tr></thead><tbody>${body}</tbody>`;
    }

    function invoiceTableMarkup(rows) {
      const labels = { paid: 'Đã thanh toán', pending: 'Đang chờ', expired: 'Hết hạn', cancelled: 'Đã hủy', failed: 'Thất bại' };
      const body = rows.length ? rows.map(row => {
        const success = row.status === 'paid';
        const date = row.paid_at || row.created_at;
        const credits = Number(row.credits_granted || 0);
        const walletAmount = Number(row.wallet_amount_vnd || 0);
        const isWallet = row.order_type === 'wallet_topup';
        const productLabels = { chatbox_ai: 'Chatbox AI', magazine_export: 'Xuất Word/PDF', magazine_ai_review: 'AI Review' };
        const invoiceType = isWallet ? 'Nạp số dư' : productLabels[row.product_code] || row.service_plan_id || row.plan_id || 'Gói dịch vụ';
        return `<tr><td data-label="Ngày">${escapeHTML(formatPortalDate(date, '-'))}</td><td data-label="Mã hóa đơn"><strong>${escapeHTML(row.payment_code || row.id || '')}</strong><small style="display:block;color:#64748b;margin-top:3px;">${escapeHTML(invoiceType)}</small></td><td data-label="Khách hàng">${escapeHTML(row.name || 'Người dùng')}<small style="display:block;color:#64748b;margin-top:3px;">${escapeHTML(row.email || '')}</small></td><td data-label="Số tiền">${formatVnd(row.amount_vnd)}</td><td data-label="Lượt / Số dư">${isWallet ? formatVnd(walletAmount || row.amount_vnd) : credits ? `${credits.toLocaleString('vi-VN')} lượt` : '-'}</td><td data-label="Trạng thái"><span class="portal-pill ${success ? 'green' : 'orange'}">${escapeHTML(labels[row.status] || row.status || '-')}</span></td></tr>`;
      }).join('') : '<tr><td colspan="6" data-label="" style="text-align:center;color:#64748b;">Chưa có hóa đơn.</td></tr>';
      return `<thead><tr><th>Ngày</th><th>Mã hóa đơn</th><th>Khách hàng</th><th>Số tiền</th><th>Lượt / Số dư</th><th>Trạng thái</th></tr></thead><tbody>${body}</tbody>`;
    }

    function renderPortalTables() {
      const accountRows = isAdminAccount() && adminDashboardData?.payments
        ? adminDashboardData.payments.slice(0, 5)
        : currentAccount?.payments || [];
      const transactionMarkup = transactionTableMarkup(accountRows);
      document.getElementById('portalTransactionTable').innerHTML = transactionMarkup;
      document.getElementById('portalTransactionFullTable').innerHTML = transactionTableMarkup(currentAccount?.payments || []);
      const users = adminDashboardData?.users || [];
      const recentInvoicesTable = document.getElementById('adminRecentInvoicesTable');
      if (recentInvoicesTable) recentInvoicesTable.innerHTML = invoiceTableMarkup((adminDashboardData?.payments || []).slice(0, 5));
      document.getElementById('adminUsersTable').innerHTML = userTableMarkup(users);
      const invoicesTable = document.getElementById('adminInvoicesTable');
      if (invoicesTable) invoicesTable.innerHTML = invoiceTableMarkup(adminDashboardData?.payments || []);
    }

    function lineChartMarkup(values, labels) {
      const width = 900;
      const height = 270;
      const pad = 28;
      const max = Math.max(...values, 1);
      const points = values.map((value, index) => {
        const x = pad + (index * (width - pad * 2)) / (values.length - 1);
        const y = height - pad - (value / max) * (height - pad * 2);
        return [x, y];
      });
      const line = points.map(point => point.join(',')).join(' ');
      const area = `${pad},${height - pad} ${line} ${width - pad},${height - pad}`;
      const grid = [0, .25, .5, .75, 1].map(step => `<line x1="${pad}" y1="${pad + step * (height - pad * 2)}" x2="${width - pad}" y2="${pad + step * (height - pad * 2)}" stroke="currentColor" opacity=".1"/>`).join('');
      const dots = points.map(([x, y]) => `<circle cx="${x}" cy="${y}" r="5" fill="#2f6df6"/>`).join('');
      const xLabels = labels.map((label, index) => `<text x="${points[index][0]}" y="${height - 3}" text-anchor="middle" fill="currentColor" opacity=".55" font-size="12">${label}</text>`).join('');
      return `<svg viewBox="0 0 ${width} ${height}" preserveAspectRatio="none" aria-label="Biểu đồ đường">${grid}<polygon points="${area}" fill="#2f6df6" opacity=".09"/><polyline points="${line}" fill="none" stroke="#2f6df6" stroke-width="5" stroke-linecap="round" stroke-linejoin="round"/>${dots}${xLabels}</svg>`;
    }

    function setSegmentActive(containerId, mode) {
      document.querySelectorAll(`#${containerId} button`).forEach(button => {
        button.classList.toggle('active', button.dataset.mode === mode);
      });
    }

    function setUserChartMode(mode) {
      userChartMode = mode === 'month' ? 'month' : 'week';
      setSegmentActive('userChartFilter', userChartMode);
      renderPortalCharts();
    }

    function setAdminChartMode(mode) {
      adminChartMode = ['day', 'week', 'month'].includes(mode) ? mode : 'day';
      setSegmentActive('adminChartFilter', adminChartMode);
      renderPortalCharts();
    }

    function renderPortalCharts() {
      const usage = new Map((currentAccount?.usage_history || []).map(row => [row.usage_date, Number(row.message_count || 0)]));
      const usageDayCount = userChartMode === 'month' ? 30 : 7;
      const usageDays = Array.from({ length: usageDayCount }, (_, index) => {
        const date = new Date();
        date.setHours(0, 0, 0, 0);
        date.setDate(date.getDate() - usageDayCount + 1 + index);
        return date;
      });
      let usageValues;
      let usageLabels;
      if (userChartMode === 'month') {
        usageValues = [];
        usageLabels = [];
        for (let index = 0; index < 30; index += 5) {
          const bucket = usageDays.slice(index, index + 5);
          usageValues.push(bucket.reduce((sum, date) => sum + (usage.get(date.toISOString().slice(0, 10)) || 0), 0));
          usageLabels.push(bucket[0].toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit' }));
        }
        document.getElementById('userChartSubtitle').textContent = 'Tổng lượt sử dụng theo từng 5 ngày';
      } else {
        usageValues = usageDays.map(date => usage.get(date.toISOString().slice(0, 10)) || 0);
        usageLabels = usageDays.map(date => date.toLocaleDateString('vi-VN', { weekday: 'short' }));
        document.getElementById('userChartSubtitle').textContent = 'Theo dõi lượt sử dụng trong 7 ngày gần nhất';
      }
      document.getElementById('userUsageChart').innerHTML = lineChartMarkup(usageValues, usageLabels);

      const paid = (adminDashboardData?.payments || []).filter(row => row.status === 'paid');
      let periods = [];
      let revenueValues = [];
      if (adminChartMode === 'day') {
        periods = Array.from({ length: 7 }, (_, index) => {
          const date = new Date();
          date.setHours(0, 0, 0, 0);
          date.setDate(date.getDate() - 6 + index);
          return { start: date, end: new Date(date.getTime() + 86400000), label: date.toLocaleDateString('vi-VN', { weekday: 'short' }) };
        });
        document.getElementById('adminChartSubtitle').textContent = 'Doanh thu 7 ngày gần nhất';
      } else if (adminChartMode === 'week') {
        periods = Array.from({ length: 8 }, (_, index) => {
          const end = new Date();
          end.setHours(0, 0, 0, 0);
          end.setDate(end.getDate() - (7 - index) * 7 + 7);
          const start = new Date(end);
          start.setDate(start.getDate() - 7);
          return { start, end, label: `${start.getDate()}/${start.getMonth() + 1}` };
        });
        document.getElementById('adminChartSubtitle').textContent = 'Doanh thu 8 tuần gần nhất';
      } else {
        periods = Array.from({ length: 6 }, (_, index) => {
          const start = new Date();
          start.setHours(0, 0, 0, 0);
          start.setDate(1);
          start.setMonth(start.getMonth() - 5 + index);
          const end = new Date(start);
          end.setMonth(end.getMonth() + 1);
          return { start, end, label: `T${start.getMonth() + 1}` };
        });
        document.getElementById('adminChartSubtitle').textContent = 'Doanh thu 6 tháng gần nhất';
      }
      revenueValues = periods.map(period => paid.reduce((sum, row) => {
        const date = new Date(row.paid_at || row.created_at);
        return date >= period.start && date < period.end ? sum + Number(row.amount_vnd || 0) : sum;
      }, 0));
      document.getElementById('adminRevenueChart').innerHTML = lineChartMarkup(revenueValues, periods.map(period => period.label));
      setSegmentActive('userChartFilter', userChartMode);
      setSegmentActive('adminChartFilter', adminChartMode);
    }

    function renderAdminDashboard(data) {
      const metrics = data.metrics || {};
      document.getElementById('adminRevenueMetric').textContent = `${Number(metrics.revenue_vnd || 0).toLocaleString('vi-VN')} đ`;
      document.getElementById('adminVipMetric').textContent = Number(metrics.vip_users || 0).toLocaleString('vi-VN');
      document.getElementById('adminUsageMetric').textContent = Number(metrics.ai_uses || 0).toLocaleString('vi-VN');
      document.getElementById('adminReviewUsageMetric').textContent = Number(metrics.ai_review_uses || 0).toLocaleString('vi-VN');
      document.getElementById('adminExportUsageMetric').textContent = Number(metrics.export_uses || 0).toLocaleString('vi-VN');
      document.getElementById('adminUsersMetric').textContent = Number(metrics.total_users || 0).toLocaleString('vi-VN');
      const vipPercent = metrics.total_users ? Math.round((metrics.vip_users / metrics.total_users) * 100) : 0;
      document.getElementById('adminVipPercent').textContent = `${vipPercent}%`;
      document.getElementById('adminStandardPercent').textContent = `${100 - vipPercent}%`;
      document.getElementById('adminUserDonut').style.background = `conic-gradient(#10b981 0 ${vipPercent}%, #94a3b8 ${vipPercent}% 100%)`;
      const revenue = metrics.revenue_by_product || {};
      const revenueBreakdown = document.getElementById('adminRevenueBreakdown');
      if (revenueBreakdown) revenueBreakdown.innerHTML = [
        ['Chatbox AI', revenue.chatbox_ai],
        ['AI Review', revenue.magazine_ai_review],
        ['Xuất Word/PDF', revenue.magazine_export],
        ['Nạp ví', revenue.wallet_topup]
      ].map(([label, value]) => `<div class="portal-card"><small>${label}</small><strong>${formatVnd(value || 0)}</strong></div>`).join('');

      syncTrialPolicyForm(data.products || []);
      renderAdminServicePlans();
      renderPortalTables();
      renderPortalCharts();
    }

    function syncTrialPolicyForm(products = adminDashboardData?.products || []) {
      const chatProduct = products.find(item => item.code === 'chatbox_ai');
      const reviewProduct = products.find(item => item.code === 'magazine_ai_review');
      const trialDays = Number(chatProduct?.trial_days ?? 14);
      const trialEnabled = trialDays > 0;
      const enabledInput = document.getElementById('trialPolicyEnabled');
      const daysInput = document.getElementById('adminTrialDays');
      const chatLimitInput = document.getElementById('adminChatTrialLimit');
      const reviewLimitInput = document.getElementById('adminReviewTrialLimit');
      const preview = document.getElementById('trialPolicyDaysPreview');
      if (enabledInput) enabledInput.checked = trialEnabled;
      if (daysInput) {
        daysInput.value = trialDays;
        daysInput.disabled = !trialEnabled;
      }
      if (chatLimitInput) {
        chatLimitInput.value = Number(chatProduct?.trial_daily_limit ?? 30);
        chatLimitInput.disabled = !trialEnabled;
      }
      if (reviewLimitInput) {
        reviewLimitInput.value = Number(reviewProduct?.trial_daily_limit ?? 5);
        reviewLimitInput.disabled = !trialEnabled;
      }
      if (preview) preview.textContent = trialEnabled ? trialDays : 0;
    }

    function handleTrialPolicyToggle() {
      const enabled = document.getElementById('trialPolicyEnabled')?.checked !== false;
      document.querySelectorAll('#adminTrialDays, #adminChatTrialLimit, #adminReviewTrialLimit').forEach(input => {
        input.disabled = !enabled;
      });
      const preview = document.getElementById('trialPolicyDaysPreview');
      const days = Number(document.getElementById('adminTrialDays')?.value || 0);
      if (preview) preview.textContent = enabled ? days : 0;
    }

    const adminPlanLabels = { chatbox_ai: 'Chatbox AI', magazine_export: 'Xuất Word/PDF', magazine_ai_review: 'AI Review' };

    function ensureAdminPlanManager() {
      const container = document.getElementById('adminServicePlans');
      if (!container) return null;
      if (!document.getElementById('adminPlanToolbar')) {
        container.insertAdjacentHTML('beforebegin', `<div id="adminPlanToolbar" class="admin-plan-toolbar">
          <input id="adminPlanSearch" type="search" placeholder="Tìm theo tên hoặc mã gói">
          <select id="adminPlanProductFilter"><option value="all">Tất cả dịch vụ</option><option value="chatbox_ai">Chatbox AI</option><option value="magazine_export">Xuất Word/PDF</option><option value="magazine_ai_review">AI Review</option></select>
          <select id="adminPlanStatusFilter"><option value="all">Tất cả trạng thái</option><option value="active">Đang bán</option><option value="inactive">Đã tắt</option></select>
        </div>`);
      }
      if (!document.getElementById('adminPlanEditModal')) {
        document.body.insertAdjacentHTML('beforeend', `<div id="adminPlanEditModal" class="admin-plan-edit-modal" aria-hidden="true">
          <section class="admin-plan-edit-card" role="dialog" aria-modal="true" aria-labelledby="adminPlanEditTitle">
            <div class="portal-panel-head"><div><h3 id="adminPlanEditTitle">Chỉnh sửa gói</h3><p id="adminPlanEditImmutable"></p></div><button type="button" class="portal-btn" data-close-admin-plan-edit><i class="fas fa-xmark"></i></button></div>
            <form id="adminPlanEditForm" class="portal-form">
              <input id="adminPlanEditId" type="hidden">
              <div class="portal-field"><label>Tên gói</label><input id="adminPlanEditName" maxlength="120" required></div>
              <div class="portal-field"><label>Giá (VND)</label><input id="adminPlanEditPrice" type="number" min="0" required></div>
              <div class="portal-field"><label id="adminPlanEditCreditsLabel">Số lượt</label><input id="adminPlanEditCredits" type="number" min="1" required></div>
              <div id="adminPlanEditDurationField" class="portal-field"><label>Thời hạn (ngày)</label><input id="adminPlanEditDuration" type="number" min="1"></div>
              <p id="adminPlanEditMessage" class="vip-message"></p>
              <button class="portal-btn primary" type="submit"><i class="fas fa-floppy-disk"></i> Lưu thay đổi</button>
            </form>
          </section>
        </div>`);
      }
      if (!container.dataset.lazyBound) {
        container.dataset.lazyBound = 'true';
        container.addEventListener('scroll', () => {
          if (container.scrollTop + container.clientHeight < container.scrollHeight - 100) return;
          adminPlanVisible += 8;
          renderAdminServicePlans();
        });
      }
      return container;
    }

    function renderAdminServicePlans() {
      const container = ensureAdminPlanManager();
      if (!container) return;
      const normalized = adminPlanSearch.trim().toLowerCase();
      const plans = (adminDashboardData?.service_plans || []).filter(item => {
        const matchesText = !normalized || `${item.id} ${item.name}`.toLowerCase().includes(normalized);
        const matchesProduct = adminPlanProduct === 'all' || item.product_code === adminPlanProduct;
        const matchesStatus = adminPlanStatus === 'all' || (adminPlanStatus === 'active' ? item.active : !item.active);
        return matchesText && matchesProduct && matchesStatus;
      });
      container.innerHTML = plans.slice(0, adminPlanVisible).map(item => `<article class="admin-plan-card">
        <div class="admin-plan-card-head"><span class="admin-plan-service">${escapeHTML(adminPlanLabels[item.product_code] || item.product_code)}</span><span class="portal-pill ${item.active ? 'green' : ''}">${item.active ? 'Đang bán' : 'Đã tắt'}</span></div>
        <div class="admin-plan-title"><strong>${escapeHTML(item.name)}</strong><small>${escapeHTML(item.id)}</small></div>
        <div class="admin-plan-facts"><span><i class="fas fa-bolt"></i> ${item.credits} ${item.billing_type === 'monthly' ? 'lượt/ngày' : 'lượt'}</span><span><i class="fas fa-clock"></i> ${item.billing_type === 'monthly' ? `${item.duration_days} ngày` : 'Không hết hạn'}</span></div>
        <div class="admin-plan-card-footer"><strong>${formatVnd(item.price_vnd)}</strong><div class="admin-plan-actions"><button class="portal-btn" type="button" data-edit-service-plan="${escapeHTML(item.id)}"><i class="fas fa-pen"></i> Sửa</button><button class="portal-btn" type="button" data-toggle-service-plan="${escapeHTML(item.id)}">${item.active ? 'Ngừng bán' : 'Bật bán'}</button></div></div>
      </article>`).join('') || '<p class="portal-panel-note">Không có gói phù hợp.</p>';
    }

    function openAdminPlanEditor(planId) {
      const plan = (adminDashboardData?.service_plans || []).find(item => item.id === planId);
      if (!plan) return;
      document.getElementById('adminPlanEditId').value = plan.id;
      document.getElementById('adminPlanEditName').value = plan.name;
      document.getElementById('adminPlanEditPrice').value = plan.price_vnd;
      document.getElementById('adminPlanEditCredits').value = plan.credits;
      document.getElementById('adminPlanEditDuration').value = plan.duration_days || 30;
      document.getElementById('adminPlanEditDurationField').hidden = plan.billing_type !== 'monthly';
      document.getElementById('adminPlanEditCreditsLabel').textContent = plan.billing_type === 'monthly' ? 'Số lượt mỗi ngày' : 'Tổng số lượt';
      document.getElementById('adminPlanEditImmutable').textContent = `${adminPlanLabels[plan.product_code]} · ${plan.billing_type === 'monthly' ? 'Gói tháng' : 'Gói lượt'} · Mã ${plan.id}`;
      document.getElementById('adminPlanEditMessage').textContent = '';
      const modal = document.getElementById('adminPlanEditModal');
      modal.classList.add('open');
      modal.setAttribute('aria-hidden', 'false');
    }

    function closeAdminPlanEditor() {
      const modal = document.getElementById('adminPlanEditModal');
      modal?.classList.remove('open');
      modal?.setAttribute('aria-hidden', 'true');
    }

    async function saveAdminPlanEdit(event) {
      event.preventDefault();
      const id = document.getElementById('adminPlanEditId').value;
      const original = (adminDashboardData?.service_plans || []).find(item => item.id === id);
      if (!original) return;
      const message = document.getElementById('adminPlanEditMessage');
      try {
        const result = await apiFetch('/api/admin/service-plans', { method: 'PATCH', body: JSON.stringify({
          ...original,
          name: document.getElementById('adminPlanEditName').value,
          price_vnd: Number(document.getElementById('adminPlanEditPrice').value),
          credits: Number(document.getElementById('adminPlanEditCredits').value),
          duration_days: original.billing_type === 'monthly' ? Number(document.getElementById('adminPlanEditDuration').value) : null
        }) });
        const index = adminDashboardData.service_plans.findIndex(item => item.id === id);
        if (index >= 0) adminDashboardData.service_plans[index] = result.plan;
        closeAdminPlanEditor();
        renderAdminServicePlans();
      } catch (error) {
        message.textContent = error.message;
        message.className = 'vip-message error';
      }
    }

    function setLookupSourceMessage(message = '', type = '') {
      const element = document.getElementById('lookupSourceMessage');
      if (!element) return;
      element.textContent = message;
      element.className = `vip-message ${type}`.trim();
    }

    function stripVietnameseMarks(value = '') {
      return String(value)
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/đ/g, 'd')
        .replace(/Đ/g, 'D');
    }

    function keywordVariants(keyword = '') {
      const clean = String(keyword).trim();
      if (!clean) return [];
      const variants = new Set([
        clean,
        encodeURIComponent(clean),
        encodeURIComponent(clean).replace(/%20/g, '+'),
        clean.replace(/\s+/g, '+'),
        clean.replace(/\s+/g, '%20'),
        stripVietnameseMarks(clean),
        encodeURIComponent(stripVietnameseMarks(clean)),
        encodeURIComponent(stripVietnameseMarks(clean)).replace(/%20/g, '+')
      ]);
      return [...variants].filter(Boolean).sort((a, b) => b.length - a.length);
    }

    function showLookupDetect(template = '', matched = '') {
      const element = document.getElementById('lookupDetectMessage');
      if (!element) return;
      if (!matched) {
        element.hidden = false;
        element.className = 'lookup-detect error';
        element.innerHTML = '<i class="fas fa-circle-exclamation"></i> Chưa nhận ra từ khóa trong link. Kiểm tra lại link và từ khóa bạn đã gõ.';
        return;
      }
      element.hidden = false;
      element.className = 'lookup-detect success';
      const preview = template.length > 70 ? `...${template.slice(-70)}` : template;
      element.innerHTML = `<i class="fas fa-circle-check"></i> Đã nhận ra từ khóa <mark>${escapeHTML(matched)}</mark><span>Link này dùng được để tra cứu tự động.</span>`;
    }

    function generateLookupTemplate() {
      const linkInput = document.getElementById('lookupResultUrl');
      const keywordInput = document.getElementById('lookupSampleKeyword');
      const templateInput = document.getElementById('lookupUrlTemplate');
      const link = linkInput?.value.trim() || '';
      const keyword = keywordInput?.value.trim() || '';
      if (!link) {
        setLookupSourceMessage('Bạn dán link kết quả vào trước nha.', 'error');
        linkInput?.focus();
        return '';
      }
      if (!keyword) {
        setLookupSourceMessage('Bạn nhập lại đúng từ khóa hoặc ISSN đã gõ khi tìm.', 'error');
        keywordInput?.focus();
        return '';
      }
      let template = link;
      const matched = keywordVariants(keyword).find(variant => template.includes(variant));
      if (matched) {
        template = template.replaceAll(matched, '{{query}}');
        if (sourceType) sourceType.value = 'search';
        setLookupSourceMessage('Xong rồi. Bạn có thể bấm Xem thử để kiểm tra.', 'success');
      } else {
        if (sourceType) sourceType.value = 'search';
        setLookupSourceMessage('Chưa nhận ra từ khóa trong link. Hãy kiểm tra lại link kết quả và từ khóa đã gõ.', 'error');
      }
      if (templateInput) templateInput.value = template;
      showLookupDetect(template, matched || '');
      return template;
    }

    function resetLookupSourceForm() {
      const form = document.getElementById('lookupSourceForm');
      if (!form) return;
      form.reset();
      document.getElementById('lookupSourceId').value = '';
      document.getElementById('lookupSortOrder').value = String(nextLookupSortOrder());
      document.getElementById('lookupIsActive').checked = true;
      const detect = document.getElementById('lookupDetectMessage');
      if (detect) detect.hidden = true;
      setLookupSourceMessage();
    }

    function nextLookupSortOrder() {
      const maxOrder = adminLookupSources.reduce((max, source) => Math.max(max, Number(source.sort_order || 0)), 0);
      return maxOrder + 10;
    }

    function lookupSourcePayload() {
      const sourceType = document.getElementById('lookupSourceType')?.value || 'search';
      const existingId = document.getElementById('lookupSourceId')?.value || '';
      const existingSource = adminLookupSources.find(item => item.id === existingId);
      const manualSortOrder = Number(document.getElementById('lookupSortOrder')?.value || 0);
      const sortOrder = Number(existingSource?.sort_order || manualSortOrder || nextLookupSortOrder());
      return {
        id: existingId,
        name: document.getElementById('lookupSourceName')?.value.trim() || '',
        result_url: document.getElementById('lookupResultUrl')?.value.trim() || '',
        sample_keyword: document.getElementById('lookupSampleKeyword')?.value.trim() || '',
        url_template: document.getElementById('lookupUrlTemplate')?.value.trim() || '',
        source_type: sourceType,
        display_mode: document.getElementById('lookupDisplayMode')?.value || 'both',
        is_active: document.getElementById('lookupIsActive')?.checked !== false,
        sort_order: sortOrder
      };
    }

    async function loadAdminLookupSources() {
      if (!isAdminAccount()) return;
      const host = document.getElementById('lookupSourceList');
      if (backendUnavailable) {
        if (host) host.innerHTML = `<p class="portal-panel-note">${escapeHTML(backendUnavailableReason || 'Backend local chưa sẵn sàng. Bạn vẫn đăng nhập được, nhưng phần lưu nguồn tra cứu cần API hoạt động.')}</p>`;
        return;
      }
      if (host) host.innerHTML = '<p class="portal-panel-note">Đang tải nguồn tra cứu...</p>';
      try {
        const result = await apiFetch('/api/admin/lookup-sources');
        adminLookupSources = result.sources || [];
        renderAdminLookupSources();
      } catch (error) {
        if (host) host.innerHTML = `<p class="portal-panel-note">${escapeHTML(error.message || 'Không tải được nguồn tra cứu.')}</p>`;
      }
    }

    function renderAdminLookupSources() {
      const host = document.getElementById('lookupSourceList');
      if (!host) return;
      if (!adminLookupSources.length) {
        host.innerHTML = '<p class="portal-panel-note">Chưa có nguồn tra cứu nào.</p>';
        return;
      }
      const modeLabels = { iframe: 'Chỉ iframe', link: 'Chỉ liên kết ngoài', both: 'Iframe + liên kết ngoài' };
      host.innerHTML = adminLookupSources.map(source => `
        <article class="lookup-source-card">
          <div>
            <strong>${escapeHTML(source.name)}</strong>
            <small>${escapeHTML(modeLabels[source.display_mode] || source.display_mode || 'Iframe + liên kết ngoài')}</small>
            <code>${escapeHTML(source.url_template || '')}</code>
          </div>
          <div class="lookup-source-card-actions">
            <span class="portal-pill ${source.is_active ? 'green' : 'orange'}">${source.is_active ? 'Đang bật' : 'Đã tắt'}</span>
            <button class="portal-btn" type="button" data-edit-lookup-source="${escapeHTML(source.id)}"><i class="fas fa-pen"></i> Sửa</button>
            <button class="portal-btn" type="button" data-toggle-lookup-source="${escapeHTML(source.id)}">${source.is_active ? 'Tắt' : 'Bật'}</button>
            <button class="portal-btn danger" type="button" data-delete-lookup-source="${escapeHTML(source.id)}"><i class="fas fa-trash"></i></button>
          </div>
        </article>
      `).join('');
    }

    function editLookupSource(id) {
      const source = adminLookupSources.find(item => item.id === id);
      if (!source) return;
      document.getElementById('lookupSourceId').value = source.id;
      document.getElementById('lookupSourceName').value = source.name || '';
      document.getElementById('lookupResultUrl').value = source.result_url || '';
      document.getElementById('lookupSampleKeyword').value = source.sample_keyword || '';
      document.getElementById('lookupUrlTemplate').value = source.url_template || '';
      document.getElementById('lookupSourceType').value = source.source_type || 'search';
      document.getElementById('lookupDisplayMode').value = source.display_mode || 'both';
      document.getElementById('lookupSortOrder').value = Number(source.sort_order || nextLookupSortOrder());
      document.getElementById('lookupIsActive').checked = source.is_active !== false;
      setLookupSourceMessage(`Bạn đang sửa: ${source.name}.`, 'success');
      document.getElementById('lookupSourceName')?.focus();
    }

    async function submitLookupSource(event) {
      event.preventDefault();
      let payload = lookupSourcePayload();
      if (payload.source_type === 'search' && !payload.url_template.includes('{{query}}')) {
        generateLookupTemplate();
        payload = lookupSourcePayload();
      }
      if (payload.source_type === 'search' && !payload.url_template.includes('{{query}}')) {
        setLookupSourceMessage('Link này chưa dùng được để tự tra cứu. Bấm “Tự nhận link” hoặc kiểm tra lại từ khóa.', 'error');
        return;
      }
      setLookupSourceMessage('Đang lưu...');
      try {
        const method = payload.id ? 'PATCH' : 'POST';
        const result = await apiFetch('/api/admin/lookup-sources', { method, body: JSON.stringify(payload) });
        const saved = result.source;
        const index = adminLookupSources.findIndex(item => item.id === saved.id);
        if (index >= 0) adminLookupSources[index] = saved;
        else adminLookupSources.push(saved);
        adminLookupSources.sort((a, b) => Number(a.sort_order || 0) - Number(b.sort_order || 0));
        renderAdminLookupSources();
        resetLookupSourceForm();
        setLookupSourceMessage('Đã lưu. Người dùng sẽ thấy nguồn này trên trang tra cứu.', 'success');
      } catch (error) {
        setLookupSourceMessage(error.message || 'Chưa lưu được. Bạn thử lại giúp mình nha.', 'error');
      }
    }

    function previewLookupSource() {
      let payload = lookupSourcePayload();
      if (payload.source_type === 'search' && !payload.url_template.includes('{{query}}')) {
        generateLookupTemplate();
        payload = lookupSourcePayload();
      }
      const keyword = payload.sample_keyword || 'iatreia';
      const encoded = encodeURIComponent(keyword).replace(/%20/g, '+');
      const url = payload.source_type === 'fixed'
        ? payload.url_template || payload.result_url
        : payload.url_template.replaceAll('{{query}}', encoded);
      if (!url) {
        setLookupSourceMessage('Chưa có link để xem thử.', 'error');
        return;
      }
      window.open(url, '_blank', 'noopener,noreferrer');
    }

    async function toggleLookupSource(id) {
      const source = adminLookupSources.find(item => item.id === id);
      if (!source) return;
      try {
        const result = await apiFetch('/api/admin/lookup-sources', {
          method: 'PATCH',
          body: JSON.stringify({ ...source, is_active: !source.is_active })
        });
        Object.assign(source, result.source);
        renderAdminLookupSources();
      } catch (error) {
        setLookupSourceMessage(error.message || 'Chưa đổi được trạng thái. Bạn thử lại giúp mình nha.', 'error');
      }
    }

    async function deleteLookupSource(id) {
      if (!confirm('Bạn muốn xóa nguồn tra cứu này?')) return;
      try {
        await apiFetch(`/api/admin/lookup-sources/${encodeURIComponent(id)}`, { method: 'DELETE' });
        adminLookupSources = adminLookupSources.filter(item => item.id !== id);
        renderAdminLookupSources();
      } catch (error) {
        setLookupSourceMessage(error.message || 'Chưa xóa được. Bạn thử lại giúp mình nha.', 'error');
      }
    }

    async function copyLookupFieldValue(inputId) {
      const input = document.getElementById(inputId);
      const value = input?.value || '';
      if (!value) return;
      try {
        await navigator.clipboard.writeText(value);
        setLookupSourceMessage('Đã sao chép.', 'success');
      } catch (_) {
        input.select();
        document.execCommand('copy');
        setLookupSourceMessage('Đã sao chép.', 'success');
      }
    }

    async function loadAdminDashboard() {
      if (!isAdminAccount()) return;
      if (adminDashboardPromise) return adminDashboardPromise;
      const status = document.getElementById('adminServicePlansStatus');
      if (backendUnavailable) {
        if (status) {
          status.textContent = backendUnavailableReason || 'Backend local chưa sẵn sàng. Dashboard admin sẽ tải lại khi API hoạt động.';
          status.className = 'vip-message';
        }
        return null;
      }
      if (status) {
        status.textContent = 'Đang tải dữ liệu...';
        status.className = 'vip-message';
      }
      adminDashboardPromise = (async () => {
        let lastError;
        for (let attempt = 0; attempt < 2; attempt += 1) {
          try {
            adminDashboardData = await apiFetch('/api/admin/dashboard');
            renderAdminDashboard(adminDashboardData);
            if (status) status.textContent = '';
            return adminDashboardData;
          } catch (error) {
            lastError = error;
            if (attempt === 0 && (!error.status || error.status >= 500)) {
              await new Promise(resolve => setTimeout(resolve, 500));
              continue;
            }
            break;
          }
        }
        backendUnavailable = Boolean(!lastError?.status || lastError.status >= 500);
        backendUnavailableReason = lastError?.message || 'Backend đang tạm thời chưa sẵn sàng';
        if (status) {
          status.textContent = backendUnavailableReason;
          status.className = 'vip-message';
        }
        return null;
      })().finally(() => {
        adminDashboardPromise = null;
      });
      return adminDashboardPromise;
    }

    function scheduleAccountRealtimeRefresh(delay = 300) {
      clearTimeout(accountRealtimeTimer);
      accountRealtimeTimer = setTimeout(() => {
        if (currentSession) void refreshAccount();
      }, delay);
    }

    function scheduleAdminRealtimeRefresh(delay = 600) {
      clearTimeout(adminRealtimeTimer);
      adminRealtimeTimer = setTimeout(() => {
        if (isAdminAccount()) void loadAdminDashboard();
      }, delay);
    }

    function stopAdminRealtimeFallback() {
      if (adminRealtimeFallbackTimer) clearInterval(adminRealtimeFallbackTimer);
      adminRealtimeFallbackTimer = null;
    }

    function startAdminRealtimeFallback() {
      stopAdminRealtimeFallback();
      adminRealtimeFallbackTimer = setInterval(() => {
        if (document.hidden || !isAdminAccount()) return;
        void loadAdminDashboard();
      }, 15000);
    }

    function removeRealtimeChannel(channel) {
      if (channel) db.removeChannel(channel);
    }

    function resetRealtimeSubscriptions() {
      removeRealtimeChannel(accountRealtimeChannel);
      removeRealtimeChannel(adminRealtimeChannel);
      accountRealtimeChannel = null;
      adminRealtimeChannel = null;
      accountRealtimeUserId = null;
      clearTimeout(accountRealtimeTimer);
      clearTimeout(adminRealtimeTimer);
      stopAdminRealtimeFallback();
    }

    function syncRealtimeSubscriptions(account = currentAccount) {
      const userId = currentSession?.user?.id;
      if (!userId) {
        resetRealtimeSubscriptions();
        return;
      }

      if (!accountRealtimeChannel || accountRealtimeUserId !== userId) {
        removeRealtimeChannel(accountRealtimeChannel);
        accountRealtimeUserId = userId;
        accountRealtimeChannel = db.channel(`account-live-${userId}`)
          .on('postgres_changes', {
            event: '*',
            schema: 'public',
            table: 'payments',
            filter: `user_id=eq.${userId}`
          }, payload => {
            if (payload.new?.payment_code === activePaymentCode && payload.new?.status === 'paid') {
              void finishPaidPayment();
              return;
            }
            scheduleAccountRealtimeRefresh();
          })
          .on('postgres_changes', { event: '*', schema: 'public', table: 'user_entitlements', filter: `user_id=eq.${userId}` }, () => scheduleAccountRealtimeRefresh())
          .on('postgres_changes', { event: '*', schema: 'public', table: 'user_wallets', filter: `user_id=eq.${userId}` }, () => scheduleAccountRealtimeRefresh())
          .on('postgres_changes', { event: '*', schema: 'public', table: 'auto_renew_preferences', filter: `user_id=eq.${userId}` }, () => scheduleAccountRealtimeRefresh())
          .subscribe(status => {
            if (status === 'CHANNEL_ERROR') scheduleAccountRealtimeRefresh(1500);
          });
      }

      if (account?.role === 'admin') {
        if (!adminRealtimeChannel) {
          adminRealtimeChannel = db.channel('admin-live-dashboard')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'payments' }, () => scheduleAdminRealtimeRefresh())
            .on('postgres_changes', { event: '*', schema: 'public', table: 'profiles' }, () => scheduleAdminRealtimeRefresh())
            .on('postgres_changes', { event: '*', schema: 'public', table: 'service_usage' }, () => scheduleAdminRealtimeRefresh())
            .on('postgres_changes', { event: '*', schema: 'public', table: 'service_products' }, () => scheduleAdminRealtimeRefresh())
            .on('postgres_changes', { event: '*', schema: 'public', table: 'service_plans' }, () => scheduleAdminRealtimeRefresh())
            .subscribe(status => {
              if (status === 'CHANNEL_ERROR') scheduleAdminRealtimeRefresh(1500);
            });
        }
        if (!adminRealtimeFallbackTimer) startAdminRealtimeFallback();
      } else {
        removeRealtimeChannel(adminRealtimeChannel);
        adminRealtimeChannel = null;
        stopAdminRealtimeFallback();
      }
    }

    async function saveAdminSettings() {
      const message = document.getElementById('adminSettingsMessage');
      try {
        const trialEnabled = document.getElementById('trialPolicyEnabled')?.checked !== false;
        const result = await apiFetch('/api/admin/settings', {
          method: 'PATCH',
          body: JSON.stringify({
            trial_enabled: trialEnabled,
            trial_days: trialEnabled ? Number(document.getElementById('adminTrialDays').value) : 0,
            chat_daily_limit: trialEnabled ? Number(document.getElementById('adminChatTrialLimit').value) : 0,
            review_daily_limit: trialEnabled ? Number(document.getElementById('adminReviewTrialLimit').value) : 0
          })
        });
        adminDashboardData.products = result.products || adminDashboardData.products || [];
        syncTrialPolicyForm(adminDashboardData.products);
        renderAdminDashboard(adminDashboardData);
        message.textContent = `Đã cập nhật chính sách dùng thử cho ${Number(result.synced_trials || 0)} tài khoản đang dùng thử.`;
        message.className = 'vip-message success';
      } catch (error) {
        message.textContent = error.message || 'Chưa lưu được. Vui lòng kiểm tra lại số ngày và hạn mức.';
        message.className = 'vip-message error';
      }
    }

    // ─── Tiện ích Excel ───────────────────────────────────────────────
    function _xlsxStyleHeader(ws, headers) {
      if (typeof XLSX === 'undefined') return;
      headers.forEach((_, colIdx) => {
        const cellRef = XLSX.utils.encode_cell({ r: 0, c: colIdx });
        if (!ws[cellRef]) return;
        ws[cellRef].s = {
          font: { bold: true, color: { rgb: 'FFFFFF' } },
          fill: { fgColor: { rgb: '1E3A5F' } },
          alignment: { horizontal: 'center', vertical: 'center', wrapText: true },
          border: { bottom: { style: 'thin', color: { rgb: '94A3B8' } } }
        };
      });
    }

    function _downloadXlsx(wb, filename) {
      if (typeof XLSX === 'undefined') { alert('Thư viện xuất Excel chưa tải xong, vui lòng thử lại.'); return; }
      XLSX.writeFile(wb, filename, { bookType: 'xlsx', type: 'binary', cellStyles: true });
    }

